targets.queryText:
SELECT COALESCE(
                    CAST((julianday('now') - julianday(MAX(COALESCE(completed_at, started_at)))) * 24 * 60 AS INTEGER),
                    9999
                ) AS value
                FROM refresh_runs;

targets.rawQueryText:
SELECT COALESCE(
                    CAST((julianday('now') - julianday(MAX(COALESCE(completed_at, started_at)))) * 24 * 60 AS INTEGER),
                    9999
                ) AS value
                FROM refresh_runs;

